# Regex to validate extension name format (alphanumeric, underscores, hyphens)
EXTENSION_NAME_PATTERN = re.compile(r"^[a-zA-Z][a-zA-Z0-9_\-]*$")


def validate_extension_name(extension_name: str) -> tuple[bool, str]:
    """Validate the extension name against whitelist and format rules."""
    if not extension_name:
        return False, "Extension name cannot be empty."

    extension_name = extension_name.strip().lower()

    if not EXTENSION_NAME_PATTERN.match(extension_name):
        return False, (
            f"Invalid extension name format: '{extension_name}'. "
            "Extension names must start with a letter and contain only "
            "alphanumeric characters, underscores, or hyphens."
        )

    if extension_name not in ALLOWED_EXTENSIONS:
        return False, (
            f"Extension '{extension_name}' is not in the allowed extensions whitelist. "
            f"Allowed extensions: {', '.join(sorted(ALLOWED_EXTENSIONS))}"
        )

    return True, extension_name


def get_db_connection(host: str, port: int, dbname: str, user: str, password: str):
    """Create and return a database connection."""
    conn = psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password,
    )
    conn.autocommit = True
    return conn


def list_installed_extensions(conn) -> list[dict]:
    """List all currently installed extensions."""
    with conn.cursor() as cur:
        cur.execute(
            "SELECT extname, extversion, extrelocatable FROM pg_extension ORDER BY extname;"
        )
        rows = cur.fetchall()
        return [
            {"name": row[0], "version": row[1], "relocatable": row[2]}
            for row in rows
        ]


def install_extension(conn, extension_name: str, if_not_exists: bool = True) -> tuple[bool, str]:
    """
    Safely install a PostgreSQL extension using parameterized identifier quoting.

    Uses psycopg2.sql module to safely construct the query with proper
    identifier quoting, preventing SQL injection.
    """
    is_valid, result = validate_extension_name(extension_name)
    if not is_valid:
        return False, result

    sanitized_name = result

    try:
        with conn.cursor() as cur:
            if if_not_exists:
                query = psycopg2.sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )
            else:
                query = psycopg2.sql.SQL("CREATE EXTENSION {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )

            cur.execute(query)
            return True, f"Extension '{sanitized_name}' installed successfully."

    except psycopg2.errors.DuplicateObject:
        return False, f"Extension '{sanitized_name}' is already installed."
    except psycopg2.errors.UndefinedFile:
        return False, (
            f"Extension '{sanitized_name}' is not available on this PostgreSQL server. "
            "Please ensure the extension package is installed on the server."
        )
    except psycopg2.errors.InsufficientPrivilege:
        return False, (
            f"Insufficient privileges to install extension '{sanitized_name}'. "
            "Superuser or appropriate privileges are required."
        )
    except psycopg2.Error as e:
        return False, f"Database error installing extension '{sanitized_name}': {e}"


def uninstall_extension(conn, extension_name: str, if_exists: bool = True, cascade: bool = False) -> tuple[bool, str]:
    """Safely uninstall a PostgreSQL extension."""
    is_valid, result = validate_extension_name(extension_name)
    if not is_valid:
        return False, result

    sanitized_name = result

    try:
        with conn.cursor() as cur:
            parts = [psycopg2.sql.SQL("DROP EXTENSION")]

            if if_exists:
                parts.append(psycopg2.sql.SQL("IF EXISTS"))

            parts.append(psycopg2.sql.Identifier(sanitized_name))

            if cascade:
                parts.append(psycopg2.sql.SQL("CASCADE"))

            query = psycopg2.sql.SQL(" ").join(parts)
            cur.execute(query)
            return True, f"Extension '{sanitized_name}' uninstalled successfully."

    except psycopg2.errors.DependentObjectsStillExist:
        return False, (
            f"Cannot drop extension '{sanitized_name}' because other objects depend on it. "
            "Use cascade option to drop dependent objects as well."
        )
    except psycopg2.errors.InsufficientPrivilege:
        return False, (
            f"Insufficient privileges to uninstall extension '{sanitized_name}'."
        )
    except psycopg2.Error as e:
        return False, f"Database error uninstalling extension '{sanitized_name}': {e}"


def list_available_extensions(conn) -> list[dict]:
    """List all extensions available for installation."""
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT name, default_version, comment
            FROM pg_available_extensions
            WHERE name NOT IN (SELECT extname FROM pg_extension)
            ORDER BY name;
            """
        )
        rows = cur.fetchall()
        return [
            {"name": row[0], "version": row[1], "description": row[2]}
            for row in rows
        ]


def print_extensions_table(extensions: list[dict], title: str):
    """Pretty print extensions in a table format."""
    if not extensions:
        print(f"\n{title}: None found.")
        return

    print(f"\n{title}:")
    print("-" * 80)

    if "version" in extensions[0]:
        print(f"{'Name':<30} {'Version':<15} {'Description/Info'}")
        print("-" * 80)
        for ext in extensions:
            desc = ext.get("description") or ext.get("relocatable", "")
            if isinstance(desc, bool):
                desc = "Relocatable" if desc else "Not relocatable"
            print(f"{ext['name']:<30} {ext.get('version', 'N/A'):<15} {desc or ''}")
    else:
        for ext in extensions:
            print(f"  - {ext['name']}")

    print("-" * 80)


